import java.util.*;

class Solution {
    public int[] smallestMissingValueSubtree(int[] parents, int[] nums) {
        int n = parents.length;
        List<Set<Integer>> children = new ArrayList<>();
        for (int i = 0; i < n; ++i) {
            children.add(new HashSet<>());
        }
        for (int i = 1; i < n; ++i) {
            children.get(parents[i]).add(nums[i]);
        }

        int[] ans = new int[n];
        dfs(0, parents, nums, children, ans);
        return ans;
    }

    private void dfs(int node, int[] parents, int[] nums, List<Set<Integer>> children, int[] ans) {
        for (int child : children.get(node)) {
            dfs(child, parents, nums, children, ans);
            children.get(node).remove(child);
            children.get(node).add(ans[child]);
        }
        Iterator<Integer> it = children.get(node).lower_bound(nums[node]);
        ans[node] = (it == children.get(node).end()) ? nums[node] + 1 : *it - 1;
    }
}
```

